        prefixL[i] = prefixL[i - 1] + (s.charAt(i - 1) == 'L' ? 1 : 0);
    }

    // Precompute suffix C and T counts
    for (int i = n - 1; i >= 0; i--) {
        suffixC[i] = suffixC[i + 1] + (s.charAt(i) == 'C' ? 1 : 0);
        suffixT[i] = suffixT[i + 1] + (s.charAt(i) == 'T' ? 1 : 0);
    }

    // Calculate best position to insert 'L'
    long bestAddL = 0;
    for (int i = 0; i <= n; i++) {
        long lBefore = prefixL[i];
        long cAfter = suffixC[i];
        long tAfter = suffixT[i];
        long add = cAfter * tAfter;
        if (add > bestAddL) {
            bestAddL = add;
        }
    }

    // Calculate best position to insert 'C'
    long bestAddC = 0;
    for (int i = 0; i <= n; i++) {
        long lBefore = prefixL[i];
        long tAfter = suffixT[i];
        long add = lBefore * tAfter;
        if (add > bestAddC) {
            bestAddC = add;
        }
    }

    // Precompute prefix C counts for T insertion
    int[] prefixC = new int[n + 1];
    for (int i = 1; i <= n; i++) {
        prefixC[i] = prefixC[i - 1] + (s.charAt(i - 1) == 'C' ? 1 : 0);
    }

    // Calculate best position to insert 'T'
    long bestAddT = 0;
    for (int i = 0; i <= n; i++) {
        long lBefore = prefixL[i];
        long cBefore = prefixC[i];
        long add = lBefore * cBefore;
        if (add > bestAddT) {
            bestAddT = add;
        }
    }

    long maxAdd = Math.max(bestAddL, Math.max(bestAddC, bestAddT));
    maxLCT = originalLCT + maxAdd;

    return maxLCT;
}
